class Solution:
    def sumRootToLeaf(self, root):
        # Brute force: collect each root-to-leaf bit string, parse as int, sum.
        total = [0]
        def walk(node, bits):
            if node is None:
                return
            bits = bits + str(node.val)
            if node.left is None and node.right is None:
                total[0] += int(bits, 2)
                return
            walk(node.left, bits)
            walk(node.right, bits)
        walk(root, '')
        return total[0]

